import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { dotnetApi, dotnetCustomerApi } from '../api/axios';
import { ENDPOINTS } from '../api/config';
import { updateProfile } from '../redux/slices/authSlice';
import { toast } from 'react-toastify';
import './Subscriptions.css';

const Subscriptions = () => {
  const [plans, setPlans] = useState([]);
  const [activePlan, setActivePlan] = useState(null);
  const [selectedPlan, setSelectedPlan] = useState(null);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    loadPlans();
    loadActivePlan();
  }, []);

  const loadPlans = async () => {
    try {
      const response = await dotnetApi.get(ENDPOINTS.GET_PLANS);
      const data = response.data?.data || response.data?.Data || response.data || [];
      setPlans(Array.isArray(data) ? data : []);
      if (data.length > 0) setSelectedPlan(data[0]);
    } catch (error) {
      toast.error('Failed to load plans');
    }
    setLoading(false);
  };

  const loadActivePlan = async () => {
    try {
      const response = await dotnetCustomerApi.get(ENDPOINTS.GET_ACTIVE_PLAN);
      const data = response.data?.data || response.data?.Data;
      setActivePlan(data || null);
    } catch (error) {
      // No active plan
    }
  };

  const handlePayment = async (plan) => {
    if (!plan) return;
    setProcessing(true);

    try {
      // Use Stripe.js Checkout (web equivalent of tipsi-stripe)
      const { loadStripe } = await import('@stripe/stripe-js');
      const stripe = await loadStripe(
        process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY ||
        'pk_live_51OeCKVBOfCO7ilUowmFYObsnX52EkteSKbVLUWMFjgJ8wvo6ms40V6g0nScFJGHthYO55j1GDPl34h9OfBFLJZzs00BUHY3Xyo'
      );

      if (!stripe) {
        toast.error('Payment system unavailable');
        setProcessing(false);
        return;
      }

      // Create a token using Stripe Elements or redirect to payment
      // For web, we use a card element approach
      // Since we don't have a full Stripe Elements form, we'll use the
      // backend's payment processing endpoint with a simple flow
      const cardNumber = window.prompt('Enter card number (test: 4242424242424242):');
      if (!cardNumber) {
        setProcessing(false);
        return;
      }

      const expiry = window.prompt('Expiry (MM/YY):');
      const cvc = window.prompt('CVC:');

      if (!expiry || !cvc) {
        setProcessing(false);
        return;
      }

      // Create token
      const result = await stripe.createToken('card', {
        number: cardNumber,
        exp_month: parseInt(expiry.split('/')[0]),
        exp_year: parseInt('20' + expiry.split('/')[1]),
        cvc: cvc,
      });

      if (result.error) {
        toast.error(result.error.message);
        setProcessing(false);
        return;
      }

      // Process payment through backend
      const paymentResponse = await dotnetApi.post(ENDPOINTS.PROCESS_PAYMENT, {
        packageId: plan._id,
        charges: parseFloat(plan.Price || plan.price),
        stripeToken: result.token.id,
        stripeEmail: user?.email,
      });

      const payData = paymentResponse.data;
      if (payData?.StatusCode === 200 || payData?.statusCode === 200) {
        toast.success(payData?.Data?.Message || 'Payment successful!');
        dispatch(updateProfile({ isUserHavePlan: payData?.Data || true }));
        loadActivePlan();
      } else {
        toast.error(payData?.Message || payData?.message || 'Payment failed');
      }
    } catch (error) {
      toast.error(error.message || 'Payment failed');
    }
    setProcessing(false);
  };

  const features = [
    'Download, Copy & Share any post image or video.',
    'Unlimited live Video Calls between devices.',
    'Customize your profile with: Banners, Top-Friends, Videos & Photos.',
    'Unlimited chats, group calls and connections.',
  ];

  return (
    <div className="subscriptions-page">
      <div className="subscriptions-header">
        <button className="subscriptions-back" onClick={() => navigate(-1)}>←</button>
        <h1 className="subscriptions-title">Plans</h1>
      </div>

      {/* Active plan */}
      {activePlan && (
        <div className="subscriptions-active">
          <span className="subscriptions-active-label">Current Plan:</span>
          <span className="subscriptions-active-name">{activePlan.Name || activePlan.name || 'Active'}</span>
        </div>
      )}

      {loading && <div className="groups-loading"><div className="page-loading-spinner" /></div>}

      {!loading && (
        <>
          <h2 className="subscriptions-section-title">Social Media Plan</h2>
          <p className="subscriptions-subtitle">The most popular FriendLinq plan</p>

          {/* Plan selection */}
          <div className="subscriptions-plans">
            {plans.map((plan) => (
              <div
                key={plan._id}
                className={`subscriptions-plan-card ${selectedPlan?._id === plan._id ? 'selected' : ''}`}
                onClick={() => setSelectedPlan(plan)}
              >
                <div className="subscriptions-plan-radio">
                  <span className={`subscriptions-radio ${selectedPlan?._id === plan._id ? 'checked' : ''}`} />
                </div>
                <div className="subscriptions-plan-info">
                  <span className="subscriptions-plan-name">{plan.Name || plan.name}</span>
                  <span className="subscriptions-plan-price">
                    ${plan.Price || plan.price}/{plan.Plantype || plan.plantype || 'month'}
                  </span>
                </div>
              </div>
            ))}
          </div>

          {/* Plan details */}
          {selectedPlan && (
            <div className="subscriptions-detail-card">
              <p className="subscriptions-detail-desc">
                {selectedPlan.Description || selectedPlan.description || 'Premium plan with full features'}
              </p>

              <h3 className="subscriptions-features-title">Main Features</h3>
              <ul className="subscriptions-features">
                {features.map((f, i) => (
                  <li key={i} className="subscriptions-feature">
                    <span className="subscriptions-check">✓</span>
                    <span>{f}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}

          {/* CTA */}
          <button
            className="subscriptions-buy-btn"
            onClick={() => handlePayment(selectedPlan)}
            disabled={processing || !selectedPlan}
          >
            {processing ? 'Processing...' : 'Complete Purchase'}
          </button>
        </>
      )}

      {/* Balance */}
      <div className="subscriptions-balance-section">
        <button className="subscriptions-balance-btn" onClick={async () => {
          try {
            const res = await dotnetApi.get(ENDPOINTS.GET_BALANCE);
            const balance = res.data?.data || res.data?.Data || res.data;
            toast.info(`Balance: $${balance?.amount || balance || 0}`);
          } catch (e) {
            toast.error('Failed to get balance');
          }
        }}>
          View Balance
        </button>
      </div>
    </div>
  );
};

export default Subscriptions;
